function DriverForm({ vans, close, saved }: any) { const [form, setForm] = useState({ fullName: "", email: "", phone: "", password: "", assignedVanId: vans[0]?.id || "" }); const [error, setError] = useState(""); const update = (key: string, value: string) => setForm((old) => ({ ...old, [key]: value })); async function submit(e: React.FormEvent) { e.preventDefault(); try { await api.createDriver(form); saved(); } catch (err: any) { setError(err.message); } } return <div className="modal-backdrop" onMouseDown={close}><form className="modal small-modal" onMouseDown={(e) => e.stopPropagation()} onSubmit={submit}><div className="modal-head"><div><span className="eyebrow">DRIVER ACCESS</span><h2>Add driver account</h2><p>The driver will use these details to sign in and monitor their van.</p></div><button type="button" onClick={close}>×</button></div><div className="form-grid"><label>Full name<input required value={form.fullName} onChange={(e) => update("fullName", e.target.value)} /></label><label>Phone number<input required value={form.phone} onChange={(e) => update("phone", e.target.value)} /></label><label>Email address<input required type="email" value={form.email} onChange={(e) => update("email", e.target.value)} /></label><label>Temporary password<input required minLength={6} type="password" value={form.password} onChange={(e) => update("password", e.target.value)} /></label><label className="span-2">Assigned van<select required value={form.assignedVanId} onChange={(e) => update("assignedVanId", e.target.value)}>{vans.map((v: Van) => <option key={v.id} value={v.id}>{v.name} · {v.routeName || "No route"}</option>)}</select></label></div>{error && <div className="form-error">{error}</div>}<div className="modal-actions"><button type="button" className="secondary" onClick={close}>Cancel</button><button className="primary">Create driver account</button></div></form></div>; }

function distanceToStop(point: TrackPoint | undefined, stop: SmartStop | undefined) {
  if (!point || !stop || stop.homeLat == null || stop.homeLon == null) return null;
  const rad = (value: number) => value * Math.PI / 180, earth = 6371000;
  const dLat = rad(stop.homeLat - point.lat), dLon = rad(stop.homeLon - point.lon);
  const a = Math.sin(dLat / 2) ** 2 + Math.cos(rad(point.lat)) * Math.cos(rad(stop.homeLat)) * Math.sin(dLon / 2) ** 2;
  return Math.round(earth * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a)));
}

function SmartTrackingPage({ vans, selectedVanId, setSelectedVanId, track, setTrack, setMessage }: any) {
  const [period, setPeriod] = useState<ServicePeriod>("MORNING"); const [route, setRoute] = useState<SmartRoute | null>(null); const [busy, setBusy] = useState(false);
  const [activeTrip, setActiveTrip] = useState<Trip | null>(null);
  const loadRoute = useCallback(() => { if (!selectedVanId) return Promise.resolve(); return api.smartRoute(selectedVanId, period).then(setRoute).catch((e) => setMessage(e.message)); }, [selectedVanId, period, setMessage]);
  const loadActiveTrip = useCallback(() => { if (!selectedVanId) return Promise.resolve(); return api.activeTrip(selectedVanId).then((result) => setActiveTrip(result.trip)).catch(() => setActiveTrip(null)); }, [selectedVanId]);
  useEffect(() => { loadRoute(); const timer = window.setInterval(loadRoute, 10000); return () => clearInterval(timer); }, [loadRoute]);
  useEffect(() => { loadActiveTrip(); const timer = window.setInterval(loadActiveTrip, 15000); return () => clearInterval(timer); }, [loadActiveTrip]);
  const current = route && route.currentIndex >= 0 ? route.stops[route.currentIndex] : undefined; const next = route && route.currentIndex >= 0 ? route.stops[route.currentIndex + 1] : undefined;
  const latest = track[track.length - 1]; const distance = distanceToStop(latest, current); const arriving = distance !== null && distance <= 150;
  async function updateGps() { if (!navigator.geolocation) return setMessage("GPS is unavailable in this browser"); navigator.geolocation.getCurrentPosition(async (position) => { try { await api.sendManualLocation(selectedVanId, position.coords.latitude, position.coords.longitude); const result = await api.vanTrack(selectedVanId, startOfTodayIso()); setTrack(result.points); await loadRoute(); setMessage("Live van position updated"); } catch (e: any) { setMessage(e.message); } }, (e) => setMessage(e.message), { enableHighAccuracy: true, maximumAge: 0, timeout: 15000 }); }
  async function startJourney() { if (!selectedVanId) return; setBusy(true); try { const label = period === "MORNING" ? "Morning pick-up journey" : period === "AFTERNOON" ? "After-lunch drop-off journey" : "Evening drop-off journey"; const result = await api.createTrip(selectedVanId, label); setActiveTrip(result.trip); setMessage("Journey started. GPS updates will now be recorded under this trip."); } catch (e: any) { if (e.message?.includes("active journey")) await loadActiveTrip(); setMessage(e.message); } finally { setBusy(false); } }
  async function stopJourney() { if (!activeTrip) return; setBusy(true); try { await api.endTrip(activeTrip.id); await loadActiveTrip(); setMessage("Journey stopped and saved. You can view it in Journeys."); } catch (e: any) { setMessage(e.message); } finally { setBusy(false); } }
  async function saveLocation(stop: SmartStop) { const label = window.prompt("Name this stop (optional)", stop.stopLabel || stop.residenceRoute || "") ?? undefined; if (label === undefined) return; setBusy(true); try { await api.saveChildStop(selectedVanId, stop.id, label); await loadRoute(); setMessage(`${stop.firstName}'s exact GPS stop has been saved`); } catch (e: any) { setMessage(e.message); } finally { setBusy(false); } }
  async function complete(attendanceStatus: "PRESENT" | "ABSENT") { if (!current) return; setBusy(true); try { await api.completeSmartStop(selectedVanId, current.id, period, attendanceStatus); await loadRoute(); setMessage(attendanceStatus === "ABSENT" ? `${current.firstName} marked absent for this van round.` : `${current.firstName} marked as ${period === "MORNING" ? "picked up" : "delivered"}. Moving to the next stop.`); } catch (e: any) { setMessage(e.message); } finally { setBusy(false); } }
  async function move(index: number, direction: -1 | 1) { if (!route) return; const target = index + direction; if (target < 0 || target >= route.stops.length) return; const reordered = [...route.stops]; [reordered[index], reordered[target]] = [reordered[target], reordered[index]]; try { await api.reorderSmartStops(selectedVanId, period, reordered.map((s) => s.id)); await loadRoute(); } catch (e: any) { setMessage(e.message); } }
  return <div className="smart-tracking"><div className="smart-route-toolbar"><label>Van<select value={selectedVanId} onChange={(e) => setSelectedVanId(e.target.value)}>{vans.map((v: Van) => <option key={v.id} value={v.id}>{v.name} · {v.routeName || "No route"}</option>)}</select></label><label>Current round<select value={period} onChange={(e) => setPeriod(e.target.value as ServicePeriod)}><option value="MORNING">Morning pick-up</option><option value="AFTERNOON">After-lunch drop-off</option><option value="EVENING">Evening drop-off</option></select></label><button className={activeTrip ? "secondary journey-live-btn" : "primary"} disabled={busy} onClick={activeTrip ? stopJourney : startJourney}>{activeTrip ? "■ Stop journey" : "▶ Start journey"}</button><button className="secondary" onClick={updateGps}>⌖ Update live GPS</button><div className="route-progress"><span style={{ width: `${route?.stops.length ? (route.completedCount / route.stops.length) * 100 : 0}%` }}></span><b>{route?.completedCount || 0}/{route?.stops.length || 0} stops</b></div></div>
    <section className={`journey-session-strip ${activeTrip ? "live" : ""}`}><span>{activeTrip ? "LIVE JOURNEY RECORDING" : "NO JOURNEY STARTED"}</span><strong>{activeTrip ? activeTrip.routeName || "Active school journey" : "Start a journey before moving so GPS route lines are saved."}</strong><small>{activeTrip ? `Started ${new Date(activeTrip.startTime).toLocaleString()}` : "Attendance decides who appears on the route; Start Journey records the actual road line."}</small></section>
    <div className="smart-map-grid"><section className="panel smart-map"><LiveMap points={track} stops={route?.stops || []} activeStopId={current?.id} /></section><aside className="panel active-stop-panel">{current ? <><span className={`arrival-badge ${arriving ? "near" : ""}`}>{arriving ? "ARRIVING NOW" : distance == null ? "LOCATION NEEDED" : `${distance < 1000 ? `${distance} m` : `${(distance / 1000).toFixed(1)} km`} AWAY`}</span><div className="active-child attendance-card-child"><Avatar child={current} large /><small>{period === "MORNING" ? "PICKUP CONFIRMATION" : "DROP-OFF CONFIRMATION"}</small><h2>{current.firstName} {current.lastName}</h2><p>{current.stopLabel || current.residenceRoute || "No stop registered"}</p><div className="attendance-child-meta"><span>{current.className || "No class"}</span><span>{current.parentPhone || "No parent contact"}</span></div></div>{current.homeLat == null ? <button className="location-save" disabled={busy || !latest} onClick={() => saveLocation(current)}>⌖ Save current GPS as this child’s stop</button> : <div className="coordinate-box"><span>Saved GPS stop</span><small>{current.homeLat.toFixed(5)}, {current.homeLon?.toFixed(5)}</small><button onClick={() => saveLocation(current)}>Update location</button></div>}<div className="door-attendance-actions"><button className="primary complete-stop" disabled={busy} onClick={() => complete("PRESENT")}>✓ {period === "MORNING" ? "Confirm child picked up" : "Confirm child dropped"}</button><button className="absent-stop" disabled={busy} onClick={() => complete("ABSENT")}>○ {period === "MORNING" ? "Child absent" : "Could not drop child"}</button></div>{next && <div className="next-stop"><small>NEXT STOP</small><strong>{next.firstName} {next.lastName}</strong><span>{next.stopLabel || next.residenceRoute || "Location not registered"}</span></div>}</> : <div className="route-complete"><span>✓</span><h2>{route?.stops.length ? "Round complete" : "No children in this round"}</h2><p>{route?.stops.length ? "Every child in this route has been completed." : "Confirm today’s van attendance first, then this route will show present learners for the selected round."}</p></div>}</aside></div>
    <section className="panel route-queue"><div className="panel-head"><div><h2>Route stop order</h2><p>The system automatically moves to the first unfinished child.</p></div><span className="route-legend"><i></i> Current <i></i> Completed</span></div><div className="stop-queue">{route?.stops.map((stop, index) => <div key={stop.id} className={`${stop.completedAt ? "completed" : ""} ${stop.attendanceStatus === "ABSENT" ? "absent" : ""} ${current?.id === stop.id ? "current" : ""}`}><span className="stop-number">{stop.completedAt ? stop.attendanceStatus === "ABSENT" ? "○" : "✓" : index + 1}</span><Avatar child={stop} /><div><strong>{stop.firstName} {stop.lastName}</strong><small>{stop.className || "No class"} · {stop.stopLabel || stop.residenceRoute || "GPS stop not registered"}</small></div><span className={`gps-state ${stop.attendanceStatus === "ABSENT" ? "absent" : stop.homeLat != null ? "saved" : ""}`}>{stop.attendanceStatus === "ABSENT" ? "Absent" : stop.homeLat != null ? "GPS saved" : "Needs GPS"}</span>{!stop.completedAt && <div className="order-buttons"><button disabled={index === 0} onClick={() => move(index, -1)}>↑</button><button disabled={index === route.stops.length - 1} onClick={() => move(index, 1)}>↓</button></div>}</div>)}</div></section></div>;
}

function CameraFeed({ camera, remove }: { camera: VanCamera; remove?: () => void }) {
  const feedRef = useRef<HTMLElement>(null);
  const videoRef = useRef<HTMLVideoElement>(null); const audioRef = useRef<HTMLAudioElement>(null);
  const [zoom, setZoom] = useState(1); const [soundOn, setSoundOn] = useState(false); const [isFullscreen, setIsFullscreen] = useState(false);
  useEffect(() => { const changed = () => setIsFullscreen(document.fullscreenElement === feedRef.current); document.addEventListener("fullscreenchange", changed); return () => document.removeEventListener("fullscreenchange", changed); }, []);
  const expand = async () => { if (document.fullscreenElement === feedRef.current) await document.exitFullscreen(); else await feedRef.current?.requestFullscreen?.(); };
  const audioUrl = camera.streamType === "MJPEG" ? camera.streamUrl.replace(/\/video(?:\?.*)?$/, "/audio.wav") : "";
  async function toggleSound(event: React.MouseEvent) { event.stopPropagation(); try { if (camera.streamType === "MJPEG" && audioRef.current) { if (soundOn) audioRef.current.pause(); else { audioRef.current.src = `${audioUrl}${audioUrl.includes("?") ? "&" : "?"}live=${Date.now()}`; audioRef.current.load(); await audioRef.current.play(); } setSoundOn(!soundOn); } else if (camera.streamType === "HLS" && videoRef.current) { videoRef.current.muted = soundOn; if (!soundOn) await videoRef.current.play(); setSoundOn(!soundOn); } } catch { setSoundOn(false); } }
  function keepAudioLive() { const audio = audioRef.current; if (!audio || !audio.buffered.length) return; const liveEdge = audio.buffered.end(audio.buffered.length - 1); if (Number.isFinite(liveEdge) && liveEdge - audio.currentTime > .8) audio.currentTime = Math.max(0, liveEdge - .12); }
  useEffect(() => { if (!soundOn) return; const timer = window.setInterval(keepAudioLive, 500); return () => clearInterval(timer); }, [soundOn]);
  const mediaStyle = { transform: `scale(${zoom})` };
  return <article className="camera-feed" ref={feedRef}><div className="camera-feed-head"><div><span className="camera-live-dot"></span><strong>{camera.name}</strong><small>{camera.position} · {camera.streamType}</small></div><div className="camera-head-actions"><button className="expand-camera" onClick={expand}>⛶ Fullscreen</button>{remove && <button className="remove-camera" onClick={(event) => { event.stopPropagation(); remove(); }}>Remove</button>}</div></div><div className="camera-video" onDoubleClick={expand} title="Double-tap to view fullscreen">{camera.streamType === "MJPEG" ? <img style={mediaStyle} src={camera.streamUrl} alt={`${camera.name} live feed`} /> : camera.streamType === "WEBPAGE" ? <iframe style={mediaStyle} src={camera.streamUrl} title={camera.name} allow="autoplay; fullscreen" sandbox="allow-scripts allow-same-origin allow-forms allow-popups" /> : <video ref={videoRef} style={mediaStyle} src={camera.streamUrl} controls autoPlay muted playsInline><p>This browser cannot play the HLS feed.</p></video>}<span className="live-label">● LIVE</span><div className="camera-view-controls"><button onClick={(event) => { event.stopPropagation(); setZoom((value) => Math.max(1, value - .25)); }} disabled={zoom <= 1} title="Zoom out">−</button><span>{Math.round(zoom * 100)}%</span><button onClick={(event) => { event.stopPropagation(); setZoom((value) => Math.min(4, value + .25)); }} disabled={zoom >= 4} title="Zoom in">＋</button><button onClick={(event) => { event.stopPropagation(); setZoom(1); }} title="Reset zoom">↺</button>{camera.streamType !== "WEBPAGE" && <button className={soundOn ? "sound-on" : ""} onClick={toggleSound} title={soundOn ? "Mute" : "Hear camera audio"}>{soundOn ? "🔊" : "🔇"}</button>}<button onClick={(event) => { event.stopPropagation(); expand(); }} title="Fullscreen">⛶</button></div>{audioUrl && <audio ref={audioRef} src={audioUrl} preload="none" />}</div></article>;
}

function CameraLearnersPanel({ van }: { van?: Van }) {
  const learners = useMemo(() => {
    const byId = new Map<string, { child: VanChild; periods: ServicePeriod[] }>();
    van?.assignments.forEach((assignment) => {
      const existing = byId.get(assignment.child.id);
      if (existing) existing.periods.push(assignment.period);
      else byId.set(assignment.child.id, { child: assignment.child, periods: [assignment.period] });
    });
    return Array.from(byId.values()).sort((a, b) => `${a.child.firstName} ${a.child.lastName}`.localeCompare(`${b.child.firstName} ${b.child.lastName}`));
  }, [van]);
  return <section className="panel camera-learners-panel"><div className="panel-head"><div><h2>Learners in this van</h2><p>Photo list connected to the selected van for quick identification.</p></div><span className="count-pill">{learners.length} learners</span></div>{learners.length ? <div className="camera-learner-strip">{learners.map(({ child, periods: childPeriods }) => <article key={child.id} className="camera-learner-card"><Avatar child={child} large /><div><strong>{child.firstName} {child.lastName}</strong><small>{child.className || "No class"} · {child.residenceRoute || "No route"}</small><div className="journey-pills">{childPeriods.map((periodId) => <span key={periodId} className={`journey ${periodId.toLowerCase()}`}>{periods.find((item) => item.id === periodId)?.short}</span>)}</div></div></article>)}</div> : <Empty>No learners are assigned to this van yet.</Empty>}</section>;
}

function CameraPage({ vans, selectedVanId, setSelectedVanId, track, role, notify }: any) {
  const [cameras, setCameras] = useState<VanCamera[]>([]); const [loading, setLoading] = useState(false); const [showForm, setShowForm] = useState(false);
  const load = useCallback(() => { if (!selectedVanId) return; setLoading(true); api.cameras(selectedVanId).then((r) => setCameras(r.cameras)).catch((e) => notify(e.message)).finally(() => setLoading(false)); }, [selectedVanId, notify]);
  useEffect(() => { load(); }, [load]);
  const van = vans.find((item: Van) => item.id === selectedVanId);
  return <div className="camera-page"><div className="camera-toolbar"><label>Van<select value={selectedVanId} onChange={(e) => setSelectedVanId(e.target.value)}>{vans.map((item: Van) => <option key={item.id} value={item.id}>{item.name} · {item.plateNumber || "No plate"}</option>)}</select></label><div><span className="camera-live-dot"></span><strong>{cameras.length} connected feeds</strong><small>{van?.driverName || "No driver assigned"}</small></div>{role === "ADMIN" && <button className="primary" onClick={() => setShowForm(true)}>＋ Connect camera</button>}</div>
    <div className="camera-location-grid"><section className="panel camera-map"><div className="panel-head"><div><h2>Van location</h2><p>Live GPS and camera feeds are shown together.</p></div></div><LiveMap points={track} vanOnly /></section><section className="camera-safety-note"><span>▣</span><div><h3>Live vehicle monitoring</h3><p>Only authorised school staff and the assigned driver should access these feeds. Camera audio and video must follow your local privacy and child-protection rules.</p></div></section></div>
    <CameraLearnersPanel van={van} />
    <div className="camera-section-head"><div><h2>Live video feeds</h2><p>Inside and outside views from {van?.name || "the selected van"}</p></div></div>{loading ? <Empty>Connecting to cameras…</Empty> : cameras.length ? <div className="camera-grid">{cameras.map((camera) => <CameraFeed key={camera.id} camera={camera} remove={role === "ADMIN" ? async () => { if (!confirm(`Remove ${camera.name}?`)) return; await api.deleteCamera(camera.id); load(); notify("Camera removed"); } : undefined} />)}</div> : <div className="camera-empty"><span>▣</span><h2>No camera connected</h2><p>Connect a browser-ready HLS, MJPEG or WebRTC viewer supplied by the camera recorder.</p>{role === "ADMIN" && <button className="primary" onClick={() => setShowForm(true)}>Connect first camera</button>}</div>}
    {showForm && <CameraForm vans={vans} initialVanId={selectedVanId} close={() => setShowForm(false)} saved={() => { setShowForm(false); load(); notify("Camera connected successfully"); }} />}</div>;
}

function CameraForm({ vans, initialVanId, close, saved }: any) {
  const [form, setForm] = useState({ vanId: initialVanId, name: "", position: "INSIDE", streamType: "HLS", streamUrl: "" }); const [error, setError] = useState("");
  const update = (key: string, value: string) => setForm((old) => ({ ...old, [key]: key === "streamUrl" ? normaliseCameraUrl(value, old.streamType) : value }));
  async function submit(event: React.FormEvent) { event.preventDefault(); try { await api.createCamera({ ...form, streamUrl: normaliseCameraUrl(form.streamUrl, form.streamType) }); saved(); } catch (e: any) { setError(e.message); } }
  const placeholder = form.streamType === "MJPEG" ? "http://192.168.100.130:8080/video" : form.streamType === "HLS" ? "https://video.example/van/stream.m3u8" : "https://video.example/van/live";
  return <div className="modal-backdrop" onMouseDown={close}><form className="modal small-modal" onMouseDown={(e) => e.stopPropagation()} onSubmit={submit}><div className="modal-head"><div><span className="eyebrow">LIVE VIDEO</span><h2>Connect a van camera</h2><p>Use a browser-ready playback URL from the camera recorder or video gateway.</p></div><button type="button" onClick={close}>×</button></div><div className="form-grid"><label>Van<select value={form.vanId} onChange={(e) => update("vanId", e.target.value)}>{vans.map((van: Van) => <option key={van.id} value={van.id}>{van.name}</option>)}</select></label><label>Camera name<input required placeholder="e.g. Inside cabin" value={form.name} onChange={(e) => update("name", e.target.value)} /></label><label>View position<select value={form.position} onChange={(e) => update("position", e.target.value)}><option value="INSIDE">Inside cabin</option><option value="OUTSIDE">Outside</option><option value="FRONT">Front road</option><option value="REAR">Rear view</option></select></label><label>Stream type<select value={form.streamType} onChange={(e) => update("streamType", e.target.value)}><option value="HLS">HLS (.m3u8)</option><option value="MJPEG">MJPEG image stream</option><option value="WEBPAGE">WebRTC / vendor web viewer</option></select></label><label className="span-2">Playback URL<input required type="url" placeholder={placeholder} value={form.streamUrl} onChange={(e) => update("streamUrl", e.target.value)} />{form.streamType === "MJPEG" && <small className="field-tip">For Galaxy/IP Webcam testing use <b>http</b>, for example: <code>http://192.168.100.130:8080/video</code></small>}</label></div><div className="camera-help"><strong>Important connection rule</strong><p>RTSP addresses such as <code>rtsp://…</code> cannot play directly in a browser. Configure the camera’s mobile DVR or a video gateway to provide HLS, MJPEG, or a WebRTC viewer URL.</p></div>{error && <div className="form-error">{error}</div>}<div className="modal-actions"><button type="button" className="secondary" onClick={close}>Cancel</button><button className="primary">Connect camera</button></div></form></div>;
}

function DriverDashboard({ user, vans, children, go }: { user: AuthUser; vans: Van[]; children: Child[]; go: (page: Page) => void }) {
  const van = vans[0];
  const roundCounts = periods.map((item) => ({ ...item, count: children.filter((child) => child.assignments.some((assignment) => assignment.period === item.id && (!van || assignment.vanId === van.id))).length }));
  return <div className="driver-dashboard"><section className="driver-welcome-card"><div><span className="eyebrow">YOUR ASSIGNED VEHICLE</span><h2>{van?.name || user.assignedVan?.name || "No van assigned"}</h2><p>{van ? `${van.plateNumber || "No plate"} · ${van.routeName || "Route not set"}` : "Ask the administrator to assign a van to your account."}</p></div>{van ? <VanAvatar van={van} large /> : <span className="driver-dashboard-van">▰</span>}</section><section className="stats driver-stats"><div className="stat"><span className="stat-icon green">♙</span><div><small>YOUR LEARNERS</small><strong>{children.length}</strong><p>Assigned to your van</p></div></div><div className="stat"><span className="stat-icon amber">◷</span><div><small>MORNING PICK-UP</small><strong>{roundCounts[0].count}</strong><p>Expected learners</p></div></div><div className="stat"><span className="stat-icon blue">⌂</span><div><small>GOING HOME</small><strong>{roundCounts[1].count + roundCounts[2].count}</strong><p>After lunch or evening</p></div></div></section><div className="dashboard-grid"><section className="panel"><div className="panel-head"><div><h2>Today’s route rounds</h2><p>Children expected in each journey</p></div><button className="text-btn" onClick={() => go("tracking")}>Open my route →</button></div><div className="round-list">{roundCounts.map((round, index) => <div className="round-row" key={round.id}><span className={`timeline-dot p${index}`}></span><div className="round-time"><strong>{round.short}</strong><small>{index === 0 ? "Home → School" : "School → Home"}</small></div><div className="load-bar"><span style={{ width: `${children.length ? Math.min(100, round.count / children.length * 100) : 0}%` }}></span></div><strong>{round.count} children</strong></div>)}</div></section><section className="panel driver-quick-actions"><div className="panel-head"><div><h2>Driver actions</h2><p>Everything for your assigned van</p></div></div><button onClick={() => go("attendance")}><span>☑</span><div><strong>Confirm van attendance</strong><small>Mark present or absent before drop-off route</small></div>→</button><button onClick={() => go("tracking")}><span>⌖</span><div><strong>Start or continue route</strong><small>Navigate child stops and record pickup/drop-off</small></div>→</button><button onClick={() => go("children")}><span>♙</span><div><strong>View my children</strong><small>Contacts, classes and residence routes</small></div>→</button><button onClick={() => go("history")}><span>◴</span><div><strong>Today’s history</strong><small>Review completed and missed stops</small></div>→</button></section></div></div>;
}

function DriverChildrenPage({ children, search, setSearch, period, setPeriod }: any) {
  return <section className="panel table-panel"><div className="toolbar"><div className="search">⌕<input placeholder="Search your learners…" value={search} onChange={(event) => setSearch(event.target.value)} /></div><select value={period} onChange={(event) => setPeriod(event.target.value)}><option value="ALL">All travel times</option>{periods.map((item) => <option key={item.id} value={item.id}>{item.short}</option>)}</select><span className="result-count">{children.length} learners</span></div>{children.length ? <div className="table-wrap"><table><thead><tr><th>Learner</th><th>Class</th><th>Residence / stop</th><th>Parent contact</th><th>Journey</th></tr></thead><tbody>{children.map((child: Child) => <tr key={child.id}><td><div className="person"><Avatar child={child} /><strong>{child.firstName} {child.lastName}</strong></div></td><td><span className="class-pill">{child.className || "—"}</span></td><td>{child.residenceRoute || "—"}</td><td><a href={`tel:${child.parentPhone}`}>{child.parentPhone || "—"}</a></td><td><div className="journey-pills">{child.assignments.map((assignment) => <span key={assignment.period} className={`journey ${assignment.period.toLowerCase()}`}>{periods.find((item) => item.id === assignment.period)?.short}</span>)}</div></td></tr>)}</tbody></table></div> : <Empty>No learners assigned to your van match this view.</Empty>}</section>;
}

function DriverSettings({ user, changed, notify }: { user: AuthUser; changed: (user: AuthUser) => void; notify: (message: string) => void }) {
  const [profile, setProfile] = useState({ fullName: user.fullName || "", email: user.email, phone: user.phone || "" });
  const [passwords, setPasswords] = useState({ currentPassword: "", newPassword: "", confirmPassword: "" }); const [busy, setBusy] = useState(false);
  async function saveProfile(event: React.FormEvent) { event.preventDefault(); setBusy(true); try { const result = await api.updateProfile(profile); changed({ ...user, ...result.user }); } catch (error: any) { notify(error.message); } finally { setBusy(false); } }
  async function savePassword(event: React.FormEvent) { event.preventDefault(); if (passwords.newPassword !== passwords.confirmPassword) return notify("New passwords do not match"); setBusy(true); try { await api.changePassword(passwords.currentPassword, passwords.newPassword); setPasswords({ currentPassword: "", newPassword: "", confirmPassword: "" }); notify("Password changed successfully"); } catch (error: any) { notify(error.message); } finally { setBusy(false); } }
  return <div className="settings-stack"><section className="driver-account-banner"><span className="user-avatar">{initials(profile.fullName.split(" ")[0], profile.fullName.split(" ").slice(1).join(" "))}</span><div><small>DRIVER ACCOUNT</small><h2>{profile.fullName || "Driver"}</h2><p>Assigned to <b>{user.assignedVan?.name || "no van"}</b>{user.assignedVan?.routeName ? ` · ${user.assignedVan.routeName}` : ""}</p></div></section><form className="panel settings-section" onSubmit={saveProfile}><div className="panel-head"><div><h2>Personal information</h2><p>This name appears throughout your driver dashboard.</p></div></div><div className="settings-form"><label>Full name<input required value={profile.fullName} onChange={(event) => setProfile({ ...profile, fullName: event.target.value })} /></label><label>Phone number<input required value={profile.phone} onChange={(event) => setProfile({ ...profile, phone: event.target.value })} /></label><label className="span-2">Email address<input required type="email" value={profile.email} onChange={(event) => setProfile({ ...profile, email: event.target.value })} /></label></div><div className="modal-actions"><button className="primary" disabled={busy}>Save profile</button></div></form><form className="panel settings-section" onSubmit={savePassword}><div className="panel-head"><div><h2>Change password</h2><p>Use a private password with at least six characters.</p></div></div><div className="settings-form"><label>Current password<input required type="password" value={passwords.currentPassword} onChange={(event) => setPasswords({ ...passwords, currentPassword: event.target.value })} /></label><label>New password<input required minLength={6} type="password" value={passwords.newPassword} onChange={(event) => setPasswords({ ...passwords, newPassword: event.target.value })} /></label><label>Confirm new password<input required minLength={6} type="password" value={passwords.confirmPassword} onChange={(event) => setPasswords({ ...passwords, confirmPassword: event.target.value })} /></label></div><div className="modal-actions"><button className="primary" disabled={busy}>Change password</button></div></form></div>;
}

function ManagedVansPage({ vans, onEdit, onDelete }: { vans: Van[]; onEdit: (van: Van) => void; onDelete: (van: Van) => void }) {
  return <div className="van-grid">{vans.map((van) => <article className="van-card" key={van.id}><div className="van-card-top"><VanAvatar van={van} large /><div><h2>{van.name}</h2><p>{van.plateNumber || "No plate number"}</p></div><span className="status-badge">Active</span></div><div className="van-meta"><div><small>DRIVER</small><strong>{van.driverName || "Not assigned"}</strong><span>{van.driverPhone || "No phone"}</span></div><div><small>ROUTE</small><strong>{van.routeName || "Not set"}</strong><span>{van.capacity} seats</span></div></div><div className="van-rounds">{periods.map((period) => { const list = van.assignments.filter((assignment) => assignment.period === period.id); return <div key={period.id}><div><strong>{period.short}</strong><span>{periodTime(van, period.id) || "—"}</span></div><p><b>{list.length}</b> children</p><div className="avatar-stack">{list.slice(0, 5).map((assignment) => <Avatar key={assignment.child.id} child={assignment.child} />)}{list.length > 5 && <span className="avatar fallback">+{list.length - 5}</span>}</div></div>; })}</div><div className="van-card-actions"><button className="edit-action" onClick={() => onEdit(van)}>✎ Edit van</button><button className="delete-action" onClick={() => onDelete(van)}>⌫ Delete</button></div></article>)}{!vans.length && <Empty>No vans registered yet.</Empty>}</div>;
}

function ManagedVanForm({ van, close, saved }: { van: Van | null; close: () => void; saved: () => void }) {
  const [form, setForm] = useState({ name: van?.name || "", plateNumber: van?.plateNumber || "", photoData: van?.photoData || "", driverName: van?.driverName || "", driverPhone: van?.driverPhone || "", capacity: van?.capacity || 14, routeName: van?.routeName || "", morningDeparture: van?.morningDeparture || "06:30", afternoonDeparture: van?.afternoonDeparture || "14:00", eveningDeparture: van?.eveningDeparture || "17:00" }); const [error, setError] = useState(""); const [busy, setBusy] = useState(false);
  const update = (key: string, value: string | number) => setForm((current) => ({ ...current, [key]: value }));
  function photo(file?: File) { if (!file) return; if (file.size > 2_000_000) return setError("Please choose a van photo smaller than 2 MB"); const reader = new FileReader(); reader.onload = () => update("photoData", String(reader.result)); reader.readAsDataURL(file); }
  async function submit(event: React.FormEvent) { event.preventDefault(); setBusy(true); try { const payload = { ...form, capacity: Number(form.capacity) }; van ? await api.updateVan(van.id, payload) : await api.createVan(payload); saved(); } catch (failure: any) { setError(failure.message); } finally { setBusy(false); } }
  return <div className="modal-backdrop" onMouseDown={close}><form className="modal small-modal" onMouseDown={(event) => event.stopPropagation()} onSubmit={submit}><div className="modal-head"><div><span className="eyebrow">{van ? "EDIT VEHICLE" : "NEW VEHICLE"}</span><h2>{van ? `Edit ${van.name}` : "Register a van"}</h2><p>{van ? "Update its identity, driver, route, photo and departure times." : "Add its identity, photo, route, driver and round times."}</p></div><button type="button" onClick={close}>×</button></div><div className="form-grid"><label className="photo-upload van-photo-upload">{form.photoData ? <img src={form.photoData} /> : <span>＋<small>Van photo</small></span>}<input type="file" accept="image/*" onChange={(event) => photo(event.target.files?.[0])} /></label><label>Van name<input required value={form.name} onChange={(event) => update("name", event.target.value)} /></label><label>Plate number<input value={form.plateNumber} onChange={(event) => update("plateNumber", event.target.value)} /></label><label>Driver name<input value={form.driverName} onChange={(event) => update("driverName", event.target.value)} /></label><label>Driver phone<input type="tel" value={form.driverPhone} onChange={(event) => update("driverPhone", event.target.value)} /></label><label>Route name<input value={form.routeName} onChange={(event) => update("routeName", event.target.value)} /></label><label>Passenger capacity<input required type="number" min="1" max="100" value={form.capacity} onChange={(event) => update("capacity", Number(event.target.value))} /></label><label>Morning departure<input type="time" value={form.morningDeparture} onChange={(event) => update("morningDeparture", event.target.value)} /></label><label>After-lunch departure<input type="time" value={form.afternoonDeparture} onChange={(event) => update("afternoonDeparture", event.target.value)} /></label><label>Evening departure<input type="time" value={form.eveningDeparture} onChange={(event) => update("eveningDeparture", event.target.value)} /></label></div>{error && <div className="form-error">{error}</div>}<div className="modal-actions"><button type="button" className="secondary" onClick={close}>Cancel</button><button className="primary" disabled={busy}>{busy ? "Saving…" : van ? "Save changes" : "Register van"}</button></div></form></div>;
}
